  'English Literature':   ['english literature','literature hl','literature sl','world literature'],
  'History':              ['history hl','history sl','authoritarian','cold war','causes of war','rights protest','history paper'],
  'Geography':            ['geography','geographic','geog hl','geog sl'],
  'Economics':            ['economics','econ hl','econ sl','macroeconomics','microeconomics'],
  'Psychology':           ['psychology','psych hl','psych sl','psychological','cognitive','biological approach'],
  'Business Management':  ['business management','business hl','business sl','bm hl','bm sl'],
  'Physics':              ['physics','phys hl','phys sl','mechanics','electromagnetism'],
  'Chemistry':            ['chemistry','chem hl','chem sl','organic chemistry','stoichiometry'],
  'Biology':              ['biology','biol hl','biol sl','ecology','genetics','evolution'],
  'Sports Science':       ['sports science','sport science','sports exercise','exercise and health','health science','exercise health','physical education','sport and exercise','sports hl','sports sl','ess sl','ess hl','sport exercise health','sports exercise health'],
  'Computer Science':     ['computer science','computing','comp sci','cs hl','cs sl','algorithms'],
  'Environmental Systems':['environmental systems','env systems','ess','ecosystem','ecology'],
  'French':               ['french','français','langue française'],
