// Helper: get questions for a subject + topic, optionally filtered by level/difficulty
function getPreBuiltQuestions(subject, topic, opts = {}) {
  const bank = PBQ[subject];
  if (!bank) return [];
  let qs = bank.filter(q => q[1] === topic || !topic);
  if (opts.level) qs = qs.filter(q => q[3] === 's' || q[3] === opts.level);
  if (opts.difficulty) qs = qs.filter(q => q[5] === opts.difficulty);
  if (opts.subtopic) qs = qs.filter(q => q[2].toLowerCase().includes(opts.subtopic.toLowerCase()));
  return qs.map(q => ({ id: q[0], topic: q[1], subtopic: q[2], level: q[3], marks: q[4], difficulty: q[5], text: q[6], ...(q[7] ? { source_material: q[7] } : {}) }));
}

// Shared traffic light helper — used by Chapter Master, Today tab, Intel tab
function calcTrafficLight(curG, tgtG, smMode = false) {
  if (!curG) return { color: '#4b5563', bg: '#f8fafc', label: 'No data yet', icon: '⚪', emoji: '⚪' };
  if (curG >= tgtG) return { color: '#10b981', bg: '#f0fdf4', label: smMode ? 'Combat-Ready' : 'On Target', icon: '🟢', emoji: '🟢' };
  if (curG >= tgtG - 1) return { color: '#f59e0b', bg: '#fffbeb', label: 'Getting Close', icon: '🟡', emoji: '🟡' };
  return { color: '#ef4444', bg: '#fef2f2', label: 'Needs Focus', icon: '🔴', emoji: '🔴' };
}

// ─── RANK SYSTEM ─────────────────────────────────────────────────────────────
const RANKS = [
  { grade: 1, name: 'Neophyte',      nameShort: 'Neophyte',  color: '#64748b', glow: '#4b5563', bg: '#f1f5f9', symbol: 'N' },
  { grade: 2, name: 'Scout',         nameShort: 'Scout',     color: '#475569', glow: '#4b5563', bg: '#e2e8f0', symbol: 'S' },
  { grade: 3, name: 'Initiate',      nameShort: 'Initiate',  color: '#0D7377', glow: '#0D7377', bg: '#e8f6f7', symbol: 'I' },
  { grade: 4, name: 'Battle-Brother',nameShort: 'B-Brother', color: '#1E6F8E', glow: '#22d3ee', bg: '#dbeafe', symbol: 'B' },
  { grade: 5, name: 'Sergeant',      nameShort: 'Sergeant',  color: '#D97706', glow: '#f59e0b', bg: '#fffbeb', symbol: 'S5' },
  { grade: 6, name: 'Veteran',       nameShort: 'Veteran',   color: '#B8860B', glow: '#fbbf24', bg: '#fef9c3', symbol: 'V' },
  { grade: 7, name: 'Chapter Master',nameShort: 'Master',    color: '#D97706', glow: '#fde68a', bg: '#fff8e7', symbol: 'CM', animated: true }
];
function gradeToRank(avgGrade) {
  if (!avgGrade || isNaN(avgGrade)) return null;
  const g = Math.round(parseFloat(avgGrade));
  const clamped = Math.max(1, Math.min(7, g));
  return RANKS[clamped - 1];
}
function getSubjectAvgGrade(subjectName, progressData) {
  const sp = progressData[subjectName] || {};
  const grades = Object.entries(sp).filter(([k]) => !k.startsWith('grade_')).flatMap(([, d]) => d?.grades || []);
  if (!grades.length) return null;
  return grades.reduce((a, b) => a + b, 0) / grades.length;
}
// Falls back to setup grade (currentGrade) when no session data exists
function getSubjectEffectiveGrade(subjectName, progressData, userSubjects) {
  const avg = getSubjectAvgGrade(subjectName, progressData);
  if (avg !== null) return avg;
  const sub = (userSubjects || []).find(s => s.name === subjectName);
  return sub?.currentGrade || null;
}

