const XPExplainerToast = ({ onClose }) => (
  <div className="fixed top-20 right-6 z-50 bg-slate-900 border border-yellow-600 rounded-xl p-4 max-w-xs shadow-2xl">
    <p className="text-yellow-400 font-black text-sm mb-2">⚡ Two Currencies</p>
    <p className="text-slate-300 text-xs mb-1"><strong className="text-white">XP</strong> — earned by studying. Unlocks ranks and rewards.</p>
    <p className="text-slate-300 text-xs mb-3"><strong className="text-white">Commendations</strong> — earned by high grades. Used in the Rewards armoury.</p>
    <button onClick={onClose} className="text-xs text-teal-400 font-bold hover:underline">Understood →</button>
  </div>
)

const ComebackBanner = ({ xp, days, onClose }) => {
  useEffect(() => {
    const t = setTimeout(onClose, 5000)
    return () => clearTimeout(t)
  }, [onClose])
  return (
    <div className="fixed top-6 right-6 z-50 bg-gradient-to-r from-slate-800 to-slate-700 border border-teal-500 rounded-xl p-4 max-w-xs shadow-2xl" style={{ animation: 'slideUpFade 5s ease forwards' }}>
      <p className="text-teal-400 font-black text-sm">⚔️ The Warrior Returns</p>
      <p className="text-slate-300 text-xs mt-1">Absent for {days} days. The Chapter has not forgotten you.</p>
      <p className="text-yellow-400 text-xs font-bold mt-1">+{xp} Comeback XP — Resume your crusade.</p>
    </div>
  )
}

const StreakLossBanner = ({ prevStreak, onClose }) => {
  useEffect(() => {
    const t = setTimeout(onClose, 6000)
    return () => clearTimeout(t)
  }, [onClose])
  return (
    <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-50 max-w-sm w-full mx-4 bg-slate-900 border border-slate-600 rounded-2xl p-5 shadow-2xl" style={{ animation: 'slideUpFade 6s ease forwards' }}>
      <div className="flex gap-3 items-start">
        <span className="text-2xl mt-0.5">🛡️</span>
        <div>
          <p className="font-black text-white text-sm">{prevStreak}-Day Streak Broken</p>
          <p className="text-slate-400 text-xs mt-1">A {prevStreak}-day campaign ended — but the war is not lost. Return tomorrow and rebuild. Your Chapter remembers your service.</p>
          <button onClick={onClose} className="mt-3 text-xs text-teal-400 font-bold hover:underline">Resume Tomorrow →</button>
        </div>
      </div>
    </div>
  )
}

