  // Daily multiplier: random XP boost (1x, 1.5x, 2x, 3x) — changes daily
  const getDailyMultiplier = () => {
    const seed = dayKey(); // same result all day
    const hash = seed.split('').reduce((a, c) => a + c.charCodeAt(0), 0);
    const roll = hash % 100;
    if (roll < 5) return { mult: 3, label: '3× XP Day!', emoji: '🔥', color: '#ef4444', rare: true };
    if (roll < 20) return { mult: 2, label: '2× XP Day', emoji: '⚡', color: '#f59e0b', rare: false };
    if (roll < 45) return { mult: 1.5, label: '1.5× XP', emoji: '✨', color: '#10b981', rare: false };
    return { mult: 1, label: '', emoji: '', color: '', rare: false };
  };
