  /* ── Content validator: catch data-less questions before Basti sees them ── */
  const validateQuestionContent = useCallback((questions) => {
    const flagged = [];
    const valid = [];
    questions.forEach((q, i) => {
      // Skip pre-validated / approved / quality-checked questions — they are DONE
      if (q.qdbStatus === 'approved' || q.qdbStatus === 'quality-checked' || q.reviewed === true || q.preAudited === true) {
        valid.push(q);
        return;
      }
      const text = (q.text || '').toLowerCase();
      const hasDataRef = (
        /the following (graph|table|data|diagram|figure|chart|matrix|coordinates|information)/i.test(text) ||
        /refer to (the )?(graph|table|data|figure|diagram)/i.test(text) ||
        /from (the )?(table|graph|data|figure|diagram)/i.test(text) ||
        /using (the )?(following|above|given) (data|values|table|graph)/i.test(text)
      );
      const hasCoordRef = /coordinates|voronoi|delaunay|six (weather|points|locations)/i.test(text);
      const hasGraphRef = /weighted graph|hamiltonian|eulerian|adjacency matrix/i.test(text) && !/\[\[|\|.*\|/.test(text);
      const hasMarkovRef = /markov chain|transition (matrix|probabilities)/i.test(text);
      // Check if data is actually present in the question
      const hasDataBlock = (
        q.source_material ||
        /\[\[/.test(q.text) || // matrix notation
        /\|.*\|/.test(q.text) || // table
        /\d+\.\d+.*\d+\.\d+.*\d+\.\d+/.test(q.text) || // probability values
        /\(-?\d+[\.,]-?\d+\)/.test(q.text) || // coordinates
        /\[DATA/.test(q.text) || /\[DIAGRAM/.test(q.text) // explicit blocks
      );
      const isFlagged = (hasDataRef || hasCoordRef || hasGraphRef || hasMarkovRef) && !hasDataBlock;
      if (isFlagged) {
        flagged.push({ index: i, reason: hasCoordRef ? 'Missing coordinates' : hasGraphRef ? 'Missing graph data' : hasMarkovRef ? 'Missing transition matrix' : 'Missing data block' });
      } else {
        valid.push(q);
      }
    });
    return { valid, flagged, total: questions.length };
  }, []);

