        lastPracticed: data.lastPracticed,
        daysSinceLastPractice: data.lastPracticed ? Math.floor((Date.now() - new Date(data.lastPracticed).getTime()) / 86400000) : null,
        needsWork: avg < 5 || recentAvg < 5 || (data.questionsAnswered < 5 && avg < 6),
